            <td style="padding: 8px 12px; color: var(--text-main);">${studentRoom ? 'ห้อง ' + studentRoom : (rawRoom || '-')}</td>
            <td style="padding: 8px 12px; color: var(--text-main);">${rawPhone || '-'}</td>
            <td style="padding: 8px 12px;">${passwordBadge}</td>
            <td style="padding: 8px 12px;">${statusBadge}</td>
        `;
        tbody.appendChild(tr);
    }

    countEl.textContent = rows.length - 1;
    previewSection.style.display = 'flex';

    if (validCount > 0) {
        badge.style.background = 'var(--success-bg)';
        badge.style.color = 'var(--success-text)';
        badge.textContent = `ตรวจสอบสำเร็จ (ผ่าน ${validCount} / ไม่ผ่าน ${invalidCount})`;

        btnConfirm.disabled = false;
        btnConfirm.style.opacity = '1';
        btnConfirm.style.cursor = 'pointer';
    } else {
        badge.style.background = 'var(--danger-bg)';
        badge.style.color = 'var(--danger-text)';
        badge.textContent = 'ไม่พบข้อมูลที่ผ่านเกณฑ์การตรวจสอบ';

        btnConfirm.disabled = true;
        btnConfirm.style.opacity = '0.5';
        btnConfirm.style.cursor = 'not-allowed';
    }
}

window.confirmExcelImport = function() {
    if (!window.tempParsedStudents || window.tempParsedStudents.length === 0) return;

    const importedCount = window.tempParsedStudents.length;

    window.tempParsedStudents.forEach(student => {
        leaderboardDatabase.push({
            name: student.name,
            score: 1000,
            class: student.class,
            room: student.room,
            studentId: student.code,
            nickname: null,
            gender: null,
            studentNumber: null,
            phone: student.phone || null,
            email: null,
            password: student.password
        });
